class ReActAgent:
    def __init__(self, llm, tools):
        self.llm = llm
        self.tools = tools
        self.memory = []

    def run(self, query, max_steps=5):
        for step in range(max_steps):
            # Thought
            thought = self.think(query)
            # Action
            action = self.decide_action(thought)
            # Observation
            obs = self.execute_action(action)
            self.memory.append((thought, action, obs))
            if self.is_complete(obs):
                break
        return self.generate_answer()

class AgentFramework:
    def __init__(self):
        self.llm = LLMClient()
        self.tools = ToolManager()
        self.memory = Memory()
        self.planner = Planner()

    def run(self, task):
        plan = self.planner.create_plan(task)
        for step in plan:
            result = self.execute(step)
            self.memory.store(result)
        return self.compile_results()

class MemorySystem:
    def __init__(self):
        self.short_term = []  # 短期记忆
        self.long_term = VectorStore()  # 长期记忆

    def add(self, info):
        self.short_term.append(info)
        if len(self.short_term) > 10:
            # 转移到长期记忆
            self.long_term.store(self.short_term.pop(0))

    def retrieve(self, query):
        return self.long_term.search(query, k=3)

class MCPMessage:
    def __init__(self, from_agent, to_agent, action, payload):
        self.header = {
            'from': from_agent,
            'to': to_agent,
            'timestamp': time.time()
        }
        self.body = {
            'action': action,
            'payload': payload
        }

    def to_json(self):
        return json.dumps({
            'header': self.header,
            'body': self.body
        })
